9	const TRUTHY_ENV = new Set(["true", "1", "yes", "on"]);
10	
11	export type ResolvedIrcAccount = {
12	  accountId: string;
13	  enabled: boolean;
14	  name?: string;
15	  configured: boolean;
16	  host: string;
17	  port: number;
18	  tls: boolean;
19	  nick: string;
20	  username: string;
