60	/**
61	 * Returns true when the runtime token resolver (`resolveTelegramToken`) would
62	 * block channel-level fallthrough for the given accountId.  This mirrors the
63	 * guard in `token.ts` so that status-check functions (`isConfigured`,
64	 * `unconfiguredReason`, `describeAccount`) stay consistent with the gateway
65	 * runtime behaviour.
66	 *
67	 * The guard fires when:
68	 *   1. The accountId is not the default account, AND
69	 *   2. The config has an explicit `accounts` section with entries, AND
70	 *   3. The accountId is not found in that `accounts` section.
71	 *
72	 * See: https://github.com/openclaw/openclaw/issues/53876
73	 */
74	function isBlockedByMultiBotGuard(cfg: OpenClawConfig, accountId: string): boolean {
75	  if (normalizeAccountId(accountId) === DEFAULT_ACCOUNT_ID) {
76	    return false;
77	  }
78	  const accounts = cfg.channels?.telegram?.accounts;
79	  const hasConfiguredAccounts =
80	    !!accounts &&
81	    typeof accounts === "object" &&
82	    !Array.isArray(accounts) &&
83	    Object.keys(accounts).length > 0;
84	  if (!hasConfiguredAccounts) {
85	    return false;
86	  }
87	  // Use resolveNormalizedAccountEntry (same as resolveTelegramToken in token.ts)
88	  // instead of resolveAccountEntry to handle keys that require full normalization
89	  // (e.g. "Carey Notifications" → "carey-notifications").
90	  return !resolveNormalizedAccountEntry(accounts, accountId, normalizeAccountId);
91	}
