106	export function createTelegramPluginBase(params: {
107	  setupWizard: NonNullable<ChannelPlugin<ResolvedTelegramAccount>["setupWizard"]>;
108	  setup: NonNullable<ChannelPlugin<ResolvedTelegramAccount>["setup"]>;
109	}): Pick<
110	  ChannelPlugin<ResolvedTelegramAccount>,
111	  "id" | "meta" | "setupWizard" | "capabilities" | "reload" | "configSchema" | "config" | "setup"
112	> {
113	  return createChannelPluginBase({
114	    id: TELEGRAM_CHANNEL,
115	    meta: {
116	      ...getChatChannelMeta(TELEGRAM_CHANNEL),
117	      quickstartAllowFrom: true,
118	    },
119	    setupWizard: params.setupWizard,
120	    capabilities: {
121	      chatTypes: ["direct", "group", "channel", "thread"],
122	      reactions: true,
123	      threads: true,
124	      media: true,
125	      polls: true,
126	      nativeCommands: true,
127	      blockStreaming: true,
128	    },
129	    reload: { configPrefixes: ["channels.telegram"] },
130	    configSchema: TelegramChannelConfigSchema,
131	    config: {
132	      ...telegramConfigAdapter,
133	      isConfigured: (account, cfg) => {
134	        // Use inspectTelegramAccount for a complete token resolution that includes
135	        // channel-level fallback paths not available in resolveTelegramAccount.
136	        // This ensures binding-created accountIds that inherit the channel-level
137	        // token are correctly detected as configured.
138	        // See: https://github.com/openclaw/openclaw/issues/53876
139	        if (isBlockedByMultiBotGuard(cfg, account.accountId)) {
140	          return false;
141	        }
142	        const inspected = inspectTelegramAccount({ cfg, accountId: account.accountId });
143	        // Gate on actually available token, not just "configured" — the latter
144	        // includes "configured_unavailable" (unreadable tokenFile, unresolved
145	        // SecretRef) which would pass here but fail at runtime.
146	        if (!inspected.token?.trim()) {
147	          return false;
148	        }
149	        return !findTelegramTokenOwnerAccountId({ cfg, accountId: account.accountId });
150	      },
151	      unconfiguredReason: (account, cfg) => {
152	        if (isBlockedByMultiBotGuard(cfg, account.accountId)) {
153	          return `not configured: unknown accountId "${account.accountId}" in multi-bot setup`;
154	        }
155	        const inspected = inspectTelegramAccount({ cfg, accountId: account.accountId });
156	        if (!inspected.token?.trim()) {
157	          if (inspected.tokenStatus === "configured_unavailable") {
158	            return `not configured: token ${inspected.tokenSource} is configured but unavailable`;
159	          }
160	          return "not configured";
161	        }
162	        const ownerAccountId = findTelegramTokenOwnerAccountId({
163	          cfg,
164	          accountId: account.accountId,
165	        });
166	        if (!ownerAccountId) {
167	          return "not configured";
168	        }
169	        return formatDuplicateTelegramTokenReason({
170	          accountId: account.accountId,
171	          ownerAccountId,
172	        });
173	      },
174	      describeAccount: (account, cfg) => {
175	        if (isBlockedByMultiBotGuard(cfg, account.accountId)) {
176	          return {
177	            accountId: account.accountId,
178	            name: account.name,
179	            enabled: account.enabled,
180	            configured: false,
181	            tokenSource: "none" as const,
182	          };
183	        }
184	        const inspected = inspectTelegramAccount({ cfg, accountId: account.accountId });
185	        return {
186	          accountId: account.accountId,
187	          name: account.name,
188	          enabled: account.enabled,
189	          configured:
190	            !!inspected.token?.trim() &&
191	            !findTelegramTokenOwnerAccountId({ cfg, accountId: account.accountId }),
192	          tokenSource: inspected.tokenSource,
193	        };
194	      },
195	    },
196	    setup: params.setup,
197	  }) as Pick<
198	    ChannelPlugin<ResolvedTelegramAccount>,
199	    "id" | "meta" | "setupWizard" | "capabilities" | "reload" | "configSchema" | "config" | "setup"
200	  >;
201	}
