144	function splitTelegramPlainTextChunks(text: string, limit: number): string[] {
145	  if (!text) {
146	    return [];
147	  }
148	  const normalizedLimit = Math.max(1, Math.floor(limit));
149	  const chunks: string[] = [];
150	  for (let start = 0; start < text.length; start += normalizedLimit) {
151	    chunks.push(text.slice(start, start + normalizedLimit));
152	  }
153	  return chunks;
154	}
155	
156	function splitTelegramPlainTextFallback(text: string, chunkCount: number, limit: number): string[] {
157	  if (!text) {
158	    return [];
159	  }
160	  const normalizedLimit = Math.max(1, Math.floor(limit));
161	  const fixedChunks = splitTelegramPlainTextChunks(text, normalizedLimit);
162	  if (chunkCount <= 1 || fixedChunks.length >= chunkCount) {
163	    return fixedChunks;
164	  }
165	  const chunks: string[] = [];
166	  let offset = 0;
167	  for (let index = 0; index < chunkCount; index += 1) {
168	    const remainingChars = text.length - offset;
169	    const remainingChunks = chunkCount - index;
170	    const nextChunkLength =
171	      remainingChunks === 1
172	        ? remainingChars
173	        : Math.min(normalizedLimit, Math.ceil(remainingChars / remainingChunks));
174	    chunks.push(text.slice(offset, offset + nextChunkLength));
175	    offset += nextChunkLength;
176	  }
177	  return chunks;
178	}
