### 5. **Chat Types (Direct vs Group) Handling**

In `channel.ts`, the `resolveTelegramOutboundSessionRoute` function shows the distinction:

```typescript
function resolveTelegramOutboundSessionRoute(params: {
  cfg: OpenClawConfig;
  agentId: string;
  accountId?: string | null;
  target: string;
  resolvedTarget?: { kind: string };
  threadId?: string | number | null;
}) {
  const parsed = parseTelegramTarget(params.target);
  const chatId = parsed.chatId.trim();

  const isGroup = 
    parsed.chatType === "group" ||
    (parsed.chatType === "unknown" &&
      params.resolvedTarget?.kind &&
      params.resolvedTarget.kind !== "user");

  const peerId = isGroup && resolvedThreadId 
    ? buildTelegramGroupPeerId(chatId, resolvedThreadId)  // Groups with threads
    : chatId;                                               // Direct messages

  const peer: RoutePeer = {
    kind: isGroup ? "group" : "direct",
    id: peerId,
  };

  return {
    sessionKey: threadKeys?.sessionKey ?? baseSessionKey,
    baseSessionKey,
    peer,
    chatType: isGroup ? ("group" as const) : ("direct" as const),
    from: isGroup
      ? `telegram:group:${peerId}`
      : resolvedThreadId
        ? `telegram:${chatId}:topic:${resolvedThreadId}`
        : `telegram:${chatId}`,
    to: `telegram:${chatId}`,
    threadId: resolvedThreadId,
  };
}
```

**Chat types supported:**
- `"direct"` - Private messages to users
- `"group"` - Group chats (with optional topic/thread support)
- `"channel"` - Broadcast channels
- `"thread"` - Topics within forum supergroups

