13	export function createAccountListHelpers(
14	  channelKey: string,
15	  options?: {
16	    normalizeAccountId?: (id: string) => string;
17	    allowUnlistedDefaultAccount?: boolean;
18	  },
19	) {
20	  function resolveConfiguredDefaultAccountId(cfg: OpenClawConfig): string | undefined {
21	    const channel = cfg.channels?.[channelKey] as Record<string, unknown> | undefined;
22	    const preferred = normalizeOptionalAccountId(
23	      typeof channel?.defaultAccount === "string" ? channel.defaultAccount : undefined,
24	    );
25	    if (!preferred) {
26	      return undefined;
27	    }
28	    const ids = listAccountIds(cfg);
29	    if (options?.allowUnlistedDefaultAccount) {
30	      return preferred;
31	    }
32	    if (ids.some((id) => normalizeAccountId(id) === preferred)) {
33	      return preferred;
34	    }
35	    return undefined;
36	  }
37	
38	  function listConfiguredAccountIds(cfg: OpenClawConfig): string[] {
39	    const channel = cfg.channels?.[channelKey];
40	    const accounts = (channel as Record<string, unknown> | undefined)?.accounts;
41	    if (!accounts || typeof accounts !== "object") {
42	      return [];
43	    }
44	    const ids = Object.keys(accounts as Record<string, unknown>).filter(Boolean);
45	    const normalizeConfiguredAccountId = options?.normalizeAccountId;
46	    if (!normalizeConfiguredAccountId) {
47	      return ids;
48	    }
49	    return [...new Set(ids.map((id) => normalizeConfiguredAccountId(id)).filter(Boolean))];
50	  }
51	
52	  function listAccountIds(cfg: OpenClawConfig): string[] {
53	    return listCombinedAccountIds({
54	      configuredAccountIds: listConfiguredAccountIds(cfg),
55	      fallbackAccountIdWhenEmpty: DEFAULT_ACCOUNT_ID,
56	    });
57	  }
58	
59	  function resolveDefaultAccountId(cfg: OpenClawConfig): string {
60	    return resolveListedDefaultAccountId({
61	      accountIds: listAccountIds(cfg),
62	      configuredDefaultAccountId: resolveConfiguredDefaultAccountId(cfg),
63	      allowUnlistedDefaultAccount: options?.allowUnlistedDefaultAccount,
64	    });
65	  }
66	
67	  return { listConfiguredAccountIds, listAccountIds, resolveDefaultAccountId };
68	}
