Imports status helpers from `openclaw/plugin-sdk/status-helpers` and
`openclaw/plugin-sdk/extension-shared`.

**Structure:**

```
createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin Board)",
      detailLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "real-time bulletin board with named boards and direct messages.",
      quickstartAllowFrom: true,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
      blockStreaming: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: pulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      listAccountIds: (cfg) => resolvePulseBoardAccountIds(cfg),
      resolveAccount: (cfg, accountId) => resolvePulseBoardAccount(cfg, accountId),
      isConfigured: (account) => account.configured,
      describeAccount: (account) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
      }),
    },
    groups: {
      resolveRequireMention: ({ cfg, accountId, groupId }) => {
        const account = resolvePulseBoardAccount(cfg, accountId);
        return account.config.boards?.[groupId]?.requireMention ?? false;
      },
    },
    messaging: {
      normalizeTarget: (target) => {
        const t = target.trim();
        // Keep # prefix for boards, lowercase both
        return t.startsWith("#") ? t.toLowerCase() : t.toLowerCase();
      },
      targetResolver: {
        looksLikeId: (input) => /^#?\w+/.test(input.trim()),
        hint: "<#board|username>",
      },
    },
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      buildChannelSummary: ({ snapshot }) =>
        buildPassiveChannelStatusSummary(snapshot, { channel: "pulseboard" }),
      resolveAccountSnapshot: ({ account }) => ({
        configured: account.configured,
        running: false,
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        // Simulated: a real impl would open a WebSocket to ctx.account.serverUrl
        // and call dispatchInbound* helpers on inbound messages.
        ctx.log?.info(`[pulseboard:${ctx.account.accountId}] gateway started`);
        return { stop: () => {
          ctx.log?.info(`[pulseboard:${ctx.account.accountId}] gateway stopped`);
        }};
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: "Your PulseBoard pairing request has been approved.",
      normalizeAllowEntry: (entry) => entry.trim().toLowerCase(),
      notify: async ({ cfg, id, message, accountId }) => {
        await sendPulseBoardMessage(id, message, { cfg, accountId: accountId ?? undefined });
      },
    },
  },
  security: {
    dm: {
      channelKey: "pulseboard",
      resolvePolicy: (account) => account.config.dmPolicy,
      resolveAllowFrom: (account) => account.config.allowFrom,
      policyPathSuffix: "dmPolicy",
      normalizeEntry: (raw) => raw.trim().toLowerCase(),
    },
  },
  outbound: {
    base: {
      deliveryMode: "direct",
      chunker: chunkTextForOutbound,
      chunkerMode: "markdown",
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ cfg, to, text, accountId, replyToId }) =>
        sendPulseBoardMessage(to, text, {
          cfg, accountId: accountId ?? undefined, replyTo: replyToId ?? undefined,
        }),
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
        sendPulseBoardMessage(to, mediaUrl ? `${text}\n${mediaUrl}` : text, {
          cfg, accountId: accountId ?? undefined, replyTo: replyToId ?? undefined,
        }),
    },
  },
})
```

