type PulseBoardBoardConfig = {
  enabled?: boolean;
  requireMention?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// Account-level configuration (mirrors channels.pulseboard.*)
type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  apiToken?: string | SecretInput;        // from buildSecretInputSchema()
  username?: string;
  serverUrl?: string;                     // e.g. "https://api.pulseboard.io"
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  boards?: Record<string, PulseBoardBoardConfig>;
  defaultBoard?: string;
  textChunkLimit?: number;
  markdown?: MarkdownConfig;
};

// Top-level config (supports optional multi-account)
type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

// Extended OpenClaw config
type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

// Fully resolved, normalized account (no undefined credentials)
type ResolvedPulseBoardAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;    // true iff apiToken && username are non-empty
