import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
  GroupPolicySchema,
  MarkdownConfigSchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/**
 * Zod schema for a single named board's per-board override configuration.
 */
export const PulseBoardBoardConfigSchema = z.object({
  /** Whether this board is enabled for agent interaction. */
  enabled: z.boolean().optional(),

  /** Require @mention of the bot before responding in this board. */
  requireMention: z.boolean().optional(),

  /** Allowed sender usernames for this board. */
  allowFrom: AllowFromListSchema,

  /** Optional system-prompt override for this board. */
  systemPrompt: z.string().optional(),
});

export type PulseBoardBoardConfig = z.infer<typeof PulseBoardBoardConfigSchema>;

/**
 * Zod schema for channels.pulseboard.* configuration.
 */
export const PulseBoardConfigSchema = z.object({
  /** Display name for this account. */
  name: z.string().optional(),

  /** Default account ID when multiple accounts are configured. */
  defaultAccount: z.string().optional(),

  /** Whether this channel is enabled. */
  enabled: z.boolean().optional(),

  /** PulseBoard API token. */
  apiToken: buildSecretInputSchema().optional(),

  /** PulseBoard username (your handle, without the @). */
  username: z.string().optional(),

  /** Base URL of the PulseBoard server. Defaults to https://api.pulseboard.io. */
  serverUrl: z.string().optional(),

  /** DM access policy: pairing, allowlist, open, or disabled. */
  dmPolicy: DmPolicySchema.optional(),

  /** Allowed sender usernames for direct messages. */
  allowFrom: AllowFromListSchema,

  /** Group (board) access policy: allowlist, open, or disabled. */
  groupPolicy: GroupPolicySchema.optional(),

  /** Per-board configuration overrides, keyed by board name (without #). */
  boards: z.record(PulseBoardBoardConfigSchema).optional(),

  /** Default board to post to when no target is specified. */
  defaultBoard: z.string().optional(),

  /** Override the text chunk limit (default: 4000). */
  textChunkLimit: z.number().int().min(1).max(4000).optional(),

  /** Markdown formatting overrides (tables). */
  markdown: MarkdownConfigSchema,
});

export type PulseBoardConfig = z.infer<typeof PulseBoardConfigSchema>;

/**
 * JSON Schema for the Control UI (converted from Zod).
 */
export const pulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);

