import type { OpenClawConfig } from "openclaw/plugin-sdk/core";
import { resolvePulseBoardAccount } from "./types.js";

export interface PulseBoardSendOptions {
  cfg: OpenClawConfig;
  accountId?: string | null;
  replyTo?: string | null;
}

export interface PulseBoardSendResult {
  /** The resolved destination (board name or username). */
  to: string;
  /** Simulated message ID in the format pb_<timestamp>_<random>. */
  messageId: string;
}

/**
 * Send a text message to a PulseBoard board or user via direct message.
 *
 * This is a simulated implementation for a fictional platform. In a real
 * integration, this function would POST to the PulseBoard REST API:
 *   - Board post: POST <serverUrl>/api/boards/<boardName>/messages
 *   - Direct message: POST <serverUrl>/api/dms/<username>
 * with Authorization: Bearer <apiToken>.
 *
 * @param to - `#board-name` for board posts, plain username for DMs
 * @param text - Message body to send
 * @param opts - Resolved config and options
 */
export async function sendPulseBoardMessage(
  to: string,
  text: string,
  opts: PulseBoardSendOptions,
): Promise<PulseBoardSendResult> {
  const account = resolvePulseBoardAccount({
    cfg: opts.cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard account "${account.accountId}" is not configured. ` +
        "Run `openclaw setup --channel pulseboard`.",
    );
  }

  const target = to.trim();

  // Simulated delivery — a real implementation would use fetch() here.
  // isBoard = target starts with "#" → post to a board
  // else    = direct message to a user
  const _isBoard = target.startsWith("#");
  void _isBoard; // suppress unused-variable lint for the stub

  const messageId = `pb_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;
  return { to: target, messageId };
}

/**
 * Split text into chunks at word/newline boundaries, each at most `limit`
 * characters long. Prefers newline breaks over space breaks.
 *
 * Used as the explicit outbound chunker for PulseBoard's 4000-char limit.
 */
export function chunkPulseBoardText(text: string, limit: number): string[] {
  if (text.length <= limit) {
    return [text];
  }
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > limit) {
    const window = remaining.slice(0, limit);
    const lastNewline = window.lastIndexOf("\n");
    const lastSpace = window.lastIndexOf(" ");
    // Prefer newline, then space, then hard-split at limit
    const splitAt = lastNewline > 0 ? lastNewline : lastSpace > 0 ? lastSpace : limit;
    chunks.push(remaining.slice(0, splitAt).trimEnd());
    remaining = remaining.slice(splitAt).trimStart();
  }
  if (remaining.length > 0) {
    chunks.push(remaining);
  }
  return chunks;
}

