} from "openclaw/plugin-sdk/secret-input";
import {
  createTopLevelChannelDmPolicy,
  createTopLevelChannelParsedAllowFromPrompt,
  createStandardChannelSetupStatus,
  formatDocsLink,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
  splitSetupEntries,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { resolvePulseBoardAccount } from "./types.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "Create a free account at pulseboard.io and generate an API token in Settings → API.",
  "Your username is your PulseBoard handle (without the @).",
  "Env var supported: PULSEBOARD_API_TOKEN (default account only).",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard direct messages by username.",
  "Examples:",
  "- alice",
  "- bob",
  "Multiple entries: comma-separated. Use * to allow everyone.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

/**
 * Normalize a raw allow-list entry to a canonical PulseBoard username.
 * Strips leading @, lowercases the result, and rejects empty strings.
 */
export function normalizePulseBoardAllowEntry(entry: string): string | null {
  const trimmed = entry.trim().toLowerCase().replace(/^@/, "");
  if (!trimmed) return null;
  if (trimmed === "*") return "*";
  // Usernames: alphanumeric, hyphens, underscores
  if (!/^[\w-]+$/.test(trimmed)) return null;
  return trimmed;
}

function parsePulseBoardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    const normalized = normalizePulseBoardAllowEntry(entry);
    if (normalized === null) {
      return { error: `Invalid PulseBoard username: "${entry}"` };
