  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => {
    const pbCfg = (cfg.channels as Record<string, { dmPolicy?: string }> | undefined)
      ?.pulseboard;
