import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { PAIRING_APPROVED_MESSAGE } from "openclaw/plugin-sdk/channel-status";
import {
  createChatChannelPlugin,
  DEFAULT_ACCOUNT_ID,
  formatPairingApproveHint,
  type ChannelPlugin,
} from "openclaw/plugin-sdk/core";
import { buildPassiveChannelStatusSummary } from "openclaw/plugin-sdk/extension-shared";
import {
  collectStatusIssuesFromLastError,
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";
import { pulseBoardChannelConfigSchema } from "./config-schema.js";
import { chunkPulseBoardText, sendPulseBoardMessage } from "./send.js";
import { normalizePulseBoardAllowEntry, pulseBoardSetupAdapter, pulseBoardSetupWizard } from "./setup-surface.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./types.js";

/**
 * DM security resolver: enforces dmPolicy + allowFrom access controls for
 * inbound direct messages, and surfaces config warnings via collectWarnings.
 */
const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint: formatPairingApproveHint("pulseboard"),
  normalizeEntry: (raw) => {
    // Strip leading @ and lowercase; return original trimmed on error
    const trimmed = raw.trim().toLowerCase().replace(/^@/, "");
    return trimmed || raw.trim();
  },
});

/**
 * Config adapter: provides listAccountIds, resolveAccount, defaultAccountId,
 * setAccountEnabled, deleteAccount, resolveAllowFrom, and formatAllowFrom.
 * isConfigured and describeAccount are added inline below.
 */
const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: [
    "name",
    "defaultAccount",
    "apiToken",
    "username",
    "serverUrl",
    "dmPolicy",
    "allowFrom",
    "groupPolicy",
    "boards",
    "defaultBoard",
    "textChunkLimit",
  ],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => String(entry).trim().toLowerCase().replace(/^@/, ""))
      .filter(Boolean),
});

/**
 * The PulseBoard channel plugin.
 *
 * PulseBoard is a fictional real-time bulletin board platform. Users can:
 *   - Post messages to named boards (group chat, e.g. #announcements)
 *   - Send direct messages to individual users (e.g. alice)
 *
 * Text chunk limit: 4000 characters per message.
 */
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin Board)",
      detailLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "real-time bulletin board with named boards and direct messages.",
      quickstartAllowFrom: true,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
      blockStreaming: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: pulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            username: account.username,
            serverUrl: account.serverUrl,
          },
        }),
    },
    groups: {
      /**
       * Return true if the bot should only respond to messages that @mention it
       * in a given board. Falls back to false if no per-board config exists.
       */
      resolveRequireMention: ({ cfg, accountId, groupId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        // boardId stored without #; strip it in case it was included
        const boardKey = groupId.replace(/^#/, "");
        return account.config.boards?.[boardKey]?.requireMention ?? false;
      },
    },
    messaging: {
      /**
       * Normalize a raw target string into canonical form:
       *   - Board names keep their # prefix and are lowercased (#dev → #dev)
       *   - Usernames are lowercased and have any leading @ stripped
       */
      normalizeTarget: (target) => {
        const t = target.trim();
        if (t.startsWith("#")) {
          return t.toLowerCase();
        }
        return t.toLowerCase().replace(/^@/, "");
      },
      targetResolver: {
        /** Matches board names (#dev) and plain usernames (alice, bob_99). */
        looksLikeId: (input) => /^[#@]?[\w-]+$/.test(input.trim()),
        hint: "<#board|username>",
      },
    },
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      collectStatusIssues: (accounts) =>
        collectStatusIssuesFromLastError("pulseboard", accounts),
      buildChannelSummary: ({ snapshot }) => buildPassiveChannelStatusSummary(snapshot),
      resolveAccountSnapshot: ({ account }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
      }),
    }),
    gateway: {
      /**
       * Start the PulseBoard gateway for one account.
       *
       * A real implementation would open a WebSocket to
       * `wss://<serverUrl>/ws/v1` and call dispatchInboundDirectDmWithRuntime /
       * dispatchInboundGroupMessageWithRuntime on each inbound message.
       * This stub logs startup/shutdown and returns immediately.
       */
      startAccount: async (ctx) => {
        const account = ctx.account;
        ctx.setStatus({
          accountId: account.accountId,
          username: account.username,
