import { describe, expect, it } from "vitest";
import { pulseBoardPlugin } from "./channel.js";
import { chunkPulseBoardText, sendPulseBoardMessage } from "./send.js";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
} from "./types.js";

// ---------------------------------------------------------------------------
// Plugin identity
// ---------------------------------------------------------------------------
describe("pulseBoardPlugin identity", () => {
  it("has the correct plugin id", () => {
    expect(pulseBoardPlugin.id).toBe("pulseboard");
  });

  it("has the correct meta label", () => {
    expect(pulseBoardPlugin.meta.label).toBe("PulseBoard");
  });

  it("has the correct selectionLabel", () => {
    expect(pulseBoardPlugin.meta.selectionLabel).toBe("PulseBoard (Bulletin Board)");
  });

  it("has the correct docsPath", () => {
    expect(pulseBoardPlugin.meta.docsPath).toBe("/channels/pulseboard");
  });
});

// ---------------------------------------------------------------------------
// Capabilities
// ---------------------------------------------------------------------------
describe("pulseBoardPlugin capabilities", () => {
  it("supports direct chat type", () => {
    expect(pulseBoardPlugin.capabilities.chatTypes).toContain("direct");
  });

  it("supports group chat type", () => {
    expect(pulseBoardPlugin.capabilities.chatTypes).toContain("group");
  });

  it("does not claim media support", () => {
    expect(pulseBoardPlugin.capabilities.media).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// Outbound text chunk limit
// ---------------------------------------------------------------------------
describe("pulseBoardPlugin outbound", () => {
  it("sets textChunkLimit to 4000", () => {
    expect(pulseBoardPlugin.outbound?.textChunkLimit).toBe(4000);
  });
});

// ---------------------------------------------------------------------------
// Target normalization
// ---------------------------------------------------------------------------
describe("normalizeTarget", () => {
  const normalize = pulseBoardPlugin.messaging?.normalizeTarget;

  it("lowercases a board name and keeps the # prefix", () => {
    expect(normalize?.("#Announcements")).toBe("#announcements");
  });

  it("lowercases a plain username", () => {
    expect(normalize?.("Alice")).toBe("alice");
  });

  it("strips a leading @ from a username", () => {
    expect(normalize?.("@bob")).toBe("bob");
  });

  it("lowercases a board name that is already lowercase", () => {
    expect(normalize?.("#dev")).toBe("#dev");
  });

  it("normalizes a mixed-case board name", () => {
    expect(normalize?.("#OpenClaw-Dev")).toBe("#openclaw-dev");
  });
});

// ---------------------------------------------------------------------------
// Target resolver (looksLikeId)
// ---------------------------------------------------------------------------
describe("targetResolver.looksLikeId", () => {
  const looksLike = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;

  it("recognizes a board name with #", () => {
    expect(looksLike?.("#dev")).toBe(true);
  });

  it("recognizes a plain username", () => {
    expect(looksLike?.("alice")).toBe(true);
  });

  it("recognizes a username with underscores and hyphens", () => {
    expect(looksLike?.("alice_bob-99")).toBe(true);
  });

  it("recognizes a username with leading @", () => {
    expect(looksLike?.("@charlie")).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// Account resolution
// ---------------------------------------------------------------------------
describe("resolvePulseBoardAccount", () => {
  it("returns unconfigured for an empty config", () => {
    const account = resolvePulseBoardAccount({ cfg: {} });
    expect(account.configured).toBe(false);
    expect(account.accountId).toBe("default");
  });

  it("returns configured when apiToken and username are both set", () => {
    const cfg = {
      channels: {
        pulseboard: { apiToken: "pb-tok-abc", username: "testuser" },
      },
    };
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.apiToken).toBe("pb-tok-abc");
    expect(account.username).toBe("testuser");
  });

  it("returns unconfigured when only apiToken is set (username missing)", () => {
    const cfg = {
      channels: { pulseboard: { apiToken: "pb-tok-abc" } },
    };
    expect(resolvePulseBoardAccount({ cfg }).configured).toBe(false);
  });

  it("returns unconfigured when only username is set (token missing)", () => {
    const cfg = {
      channels: { pulseboard: { username: "alice" } },
    };
    expect(resolvePulseBoardAccount({ cfg }).configured).toBe(false);
  });

  it("uses the default server URL when none is configured", () => {
    const account = resolvePulseBoardAccount({ cfg: {} });
    expect(account.serverUrl).toBe("https://api.pulseboard.io");
  });

  it("uses a custom server URL when one is configured", () => {
    const cfg = {
      channels: {
        pulseboard: {
          apiToken: "tok",
          username: "u",
          serverUrl: "https://pb.example.com",
        },
      },
    };
    expect(resolvePulseBoardAccount({ cfg }).serverUrl).toBe("https://pb.example.com");
  });

  it("trims whitespace from the username", () => {
    const cfg = {
      channels: {
        pulseboard: { apiToken: "tok", username: "  spaced  " },
      },
    };
    expect(resolvePulseBoardAccount({ cfg }).username).toBe("spaced");
  });
});

// ---------------------------------------------------------------------------
// Account ID listing
// ---------------------------------------------------------------------------
describe("listPulseBoardAccountIds", () => {
  it("returns empty array when no token is configured", () => {
    expect(listPulseBoardAccountIds({})).toHaveLength(0);
  });

  it("returns [default] when a token is present", () => {
    const cfg = {
      channels: { pulseboard: { apiToken: "tok", username: "u" } },
    };
    expect(listPulseBoardAccountIds(cfg)).toEqual(["default"]);
  });
});

// ---------------------------------------------------------------------------
// Text chunking
// ---------------------------------------------------------------------------
describe("chunkPulseBoardText", () => {
  it("returns the original text as a single chunk when under the limit", () => {
    const text = "A".repeat(3999);
    const chunks = chunkPulseBoardText(text, 4000);
    expect(chunks).toHaveLength(1);
    expect(chunks[0]).toBe(text);
  });

  it("returns the original text as a single chunk exactly at the limit", () => {
    const text = "B".repeat(4000);
    const chunks = chunkPulseBoardText(text, 4000);
    expect(chunks).toHaveLength(1);
  });

  it("splits text over the limit into multiple chunks", () => {
    // 9000-char text: chunks must each be ≤ 4000 chars
    const word = "hello ";
    const text = word.repeat(1500); // 9000 chars
    const chunks = chunkPulseBoardText(text, 4000);
    expect(chunks.length).toBeGreaterThan(1);
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(4000);
    }
  });

  it("reassembles to approximately the original text (no data loss)", () => {
    const text = "word ".repeat(900).trimEnd(); // 4499 chars
    const chunks = chunkPulseBoardText(text, 4000);
    // Rejoin with spaces (trimEnd removed trailing space from each chunk)
    const rejoined = chunks.join(" ").replace(/\s+/g, " ").trim();
    const original = text.replace(/\s+/g, " ").trim();
    expect(rejoined).toBe(original);
  });

  it("prefers splitting at newline boundaries", () => {
    const part1 = "line one\n".repeat(400); // 3600 chars
    const part2 = "line two\n".repeat(400);
    const text = part1 + part2;
    const chunks = chunkPulseBoardText(text, 4000);
    // Each chunk should end at a newline boundary (no mid-word splits)
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(4000);
    }
  });
});

// ---------------------------------------------------------------------------
// Send (simulated)
// ---------------------------------------------------------------------------
describe("sendPulseBoardMessage", () => {
  const cfg = {
    channels: { pulseboard: { apiToken: "test-tok", username: "tester" } },
  };

  it("returns a messageId and the resolved target for a board post", async () => {
    const result = await sendPulseBoardMessage("#announcements", "Hello board!", { cfg });
    expect(result.to).toBe("#announcements");
    expect(result.messageId).toMatch(/^pb_\d+_[\w]+$/);
  });

  it("returns a messageId and the resolved target for a DM", async () => {
    const result = await sendPulseBoardMessage("alice", "Hey Alice!", { cfg });
    expect(result.to).toBe("alice");
    expect(result.messageId).toMatch(/^pb_\d+_[\w]+$/);
  });

  it("throws when the account is not configured", async () => {
    await expect(
      sendPulseBoardMessage("#dev", "Hello", { cfg: {} }),
    ).rejects.toThrow(/not configured/i);
  });
});

