    const part1 = "line one\n".repeat(400); // 3600 chars
    const part2 = "line two\n".repeat(400);
    const text = part1 + part2;
    const chunks = chunkPulseBoardText(text, 4000);
    // Each chunk should end at a newline boundary (no mid-word splits)
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(4000);
    }
  });
});

